export default function capitalizeWords(sentence) {
  if (!sentence) return '';
  let result = '';
  let capitalizeNext = true;

  for (const ch of sentence) {
    if (ch === ' ') {
      result += ch;
      capitalizeNext = true;
    } else if (capitalizeNext) {
      result += ch.toUpperCase();
      capitalizeNext = false;
    } else {
      result += ch.toLowerCase();
    }
  }

  return result;
}
